export declare const GAP_POLICY_GAP = "gap";
export declare const GAP_POLICY_CONNECT = "connect";
/**
 * Time unit for time threshold expression
 * @public
 */
export type TimeUnit = 'ms' | 's' | 'min' | 'h' | 'd' | 'mo' | 'y';
/**
 * Time threshold expression. Example: 10min
 * @public
 */
export type TimeThreshold = `${number}${TimeUnit}`;
/**
 * A gap policy configuration that includes a threshold for time
 * @public
 */
export type ThresholdGapPolicy = {
    threshold: TimeThreshold;
};
/**
 * A gap policy configuration that includes a threshold for numbers
 * @public
 */
export type NumericalThresholdGapPolicy = {
    threshold: number;
};
/**
 * Whether to show gaps or interpolate "gap data points" between time-based data points
 * @public
 */
export type TimeGapPolicy = 'gap' | 'connect' | ThresholdGapPolicy;
/**
 * Whether to show gaps or interpolate "gap data points" between numerical data points
 * @public
 */
export type NumericalGapPolicy = 'connect' | NumericalThresholdGapPolicy;
